transform_js:
var studies = rawData.rows.map(function(r) { return r.study; }).reverse();
var estimates = rawData.rows.map(function(r) { return r.est; }).reverse();
var errors = rawData.rows.map(function(r) { return [[r.study, r.lo], [r.study, r.hi]]; }).reverse();
var weights = rawData.rows.map(function(r) { return r.w; }).reverse();
transformedData = { studies: studies, estimates: estimates, errors: errors, weights: weights };

echarts_js:
option = {
  title: { text: 'Meta-Analysis (Forest Plot)', left: 'center' },
  tooltip: {},
  grid: { left: '20%', right: '10%' },
  yAxis: { type: 'category', data: transformedData.studies },
  xAxis: { type: 'value', name: 'Effect Size' },
  series: [
    {
      type: 'scatter',
      data: transformedData.estimates.map(function(e, i) { return { value: [e, i], symbolSize: 6 + transformedData.weights[i] * 0.4 }; }),
      itemStyle: { color: '#5470c6' },
      z: 3
    },
    {
      type: 'custom',
      renderItem: function(params, api) {
        var low = api.coord([transformedData.errors[params.dataIndex][0][1], params.dataIndex]);
        var high = api.coord([transformedData.errors[params.dataIndex][1][1], params.dataIndex]);
        return { type: 'line', shape: { x1: low[0], y1: low[1], x2: high[0], y2: high[1] }, style: { stroke: '#333', lineWidth: 1.5 } };
      },
      data: transformedData.errors,
      z: 2
    }
  ],
  markLine: { data: [{ xAxis: 0 }] }
};
